import java.util.PriorityQueue

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val graph = Array(n.toInt()) { mutableListOf<Pair<Int, Long>>() }
    val reversedEdges = Array(n.toInt()) { mutableListOf<Pair<Int, Long>>() }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        graph[u].add(v to w)
        reversedEdges[v].add(u to w)
    }

    val heap = PriorityQueue<Triple<Long, Int, Boolean>>(compareBy { it.first })
    heap.add(Triple(0L, 0, false))

    val INF = Long.MAX_VALUE
    val dist = Array(n.toInt()) { Array(2) { INF } }
    dist[0][0] = 0

    while (heap.isNotEmpty()) {
        val (currentCost, u, usedSwitch) = heap.poll()
        if (u == n - 1) {
            return currentCost
        }
        if (currentCost > dist[u][if (usedSwitch) 1 else 0]) {
            continue
        }

        for ((v, w) in graph[u]) {
            val newCost = currentCost + w
            val switchState = if (usedSwitch) 1 else 0
            if (newCost < dist[v][switchState]) {
                dist[v][switchState] = newCost
                heap.add(Triple(newCost, v, usedSwitch))
            }
        }

        if (!usedSwitch) {
            for ((v, w) in reversedEdges[u]) {
                val newCost = currentCost + 2 * w
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost
                    heap.add(Triple(newCost, v, true))
                }
            }
        }
    }

    val res = minOf(dist[(n - 1).toInt()][0], dist[(n - 1).toInt()][1])
    return if (res != INF) res else -1
}
